import React, { useEffect, useState } from 'react';
import './StatsRow.css';

const stats = [
  { label: 'Total Revenue', value: 248920, prefix: '$', suffix: '', change: +18.4, color: '#7c6af7', icon: 'M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z' },
  { label: 'Active Users', value: 14382, prefix: '', suffix: '', change: +7.2, color: '#22d3ee', icon: 'M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z' },
  { label: 'Orders Today', value: 1247, prefix: '', suffix: '', change: +23.1, color: '#f97316', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
  { label: 'Conversion Rate', value: 4.83, prefix: '', suffix: '%', change: -1.2, color: '#a3e635', icon: 'M13 7h8m0 0v8m0-8l-8 8-4-4-6 6' },
];

function useCount(target, duration = 1500) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    let start = null;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / duration, 1);
      const eased = 1 - Math.pow(1 - p, 3);
      setVal(target * eased);
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [target, duration]);
  return val;
}

function StatCard({ stat, delay }) {
  const [visible, setVisible] = useState(false);
  useEffect(() => { setTimeout(() => setVisible(true), delay); }, [delay]);
  const count = useCount(visible ? stat.value : 0);
  const formatted = stat.suffix === '%'
    ? count.toFixed(2)
    : count >= 100000
      ? (count / 1000).toFixed(0) + 'k'
      : count >= 1000
        ? count.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g, ',')
        : count.toFixed(0);

  return (
    <div className={`stat-card ${visible ? 'visible' : ''}`} style={{ '--accent-color': stat.color }}>
      <div className="stat-top">
        <span className="stat-label">{stat.label}</span>
        <div className="stat-icon-wrap">
          <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d={stat.icon} />
          </svg>
        </div>
      </div>
      <div className="stat-value">{stat.prefix}{formatted}{stat.suffix}</div>
      <div className={`stat-change ${stat.change > 0 ? 'up' : 'down'}`}>
        <svg width="12" height="12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
          <path strokeLinecap="round" strokeLinejoin="round" d={stat.change > 0 ? 'M5 15l7-7 7 7' : 'M19 9l-7 7-7-7'} />
        </svg>
        {Math.abs(stat.change)}% vs last week
      </div>
      <div className="stat-bar">
        <div className="stat-bar-fill" style={{ width: visible ? '70%' : '0%' }} />
      </div>
    </div>
  );
}

export default function StatsRow() {
  return (
    <div className="stats-row">
      {stats.map((s, i) => <StatCard key={s.label} stat={s} delay={i * 80} />)}
    </div>
  );
}
